#!/usr/bin/env python3
"""
Deployment automation script for CI/CD pipeline.
Installs dependencies, runs tests, and packages for deployment.
"""

import subprocess
import sys
import os
import shutil
import tarfile
import json
import logging
from datetime import datetime, timezone
from pathlib import Path

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(message)s",
    handlers=[
        logging.StreamHandler(sys.stdout),
        logging.FileHandler("deployment.log"),
    ],
)
logger = logging.getLogger(__name__)

# Configuration
PROJECT_ROOT = Path(__file__).parent.resolve()
REQUIREMENTS_FILE = PROJECT_ROOT / "requirements.txt"
TEST_DIR = PROJECT_ROOT / "tests"
SRC_DIR = PROJECT_ROOT / "src"
BUILD_DIR = PROJECT_ROOT / "build"
DIST_DIR = PROJECT_ROOT / "dist"
PACKAGE_EXCLUDES = {
    "__pycache__",
    ".git",
    ".env",
    "*.pyc",
    ".pytest_cache",
    "node_modules",
    ".tox",
    "build",
    "dist",
    "deployment.log",
    ".venv",
    "venv",
}


def run_command(command, description, cwd=None, env=None):
    """Run a shell command and handle errors."""
    logger.info(f"Starting: {description}")
    logger.info(f"Command: {' '.join(command)}")

    merged_env = os.environ.copy()
    if env:
        merged_env.update(env)

    try:
        result = subprocess.run(
            command,
            cwd=cwd or PROJECT_ROOT,
            env=merged_env,
            capture_output=True,
            text=True,
            timeout=300,
        )

        if result.stdout:
            for line in result.stdout.strip().split("\n"):
                logger.info(f"  {line}")

        if result.returncode != 0:
            logger.error(f"Failed: {description}")
            if result.stderr:
                for line in result.stderr.strip().split("\n"):
                    logger.error(f"  {line}")
            return False

        logger.info(f"Completed: {description}")
        return True

    except subprocess.TimeoutExpired:
        logger.error(f"Timeout: {description} exceeded 300s limit")
        return False
    except FileNotFoundError:
        logger.error(f"Command not found: {command[0]}")
        return False
    except Exception as e:
        logger.error(f"Unexpected error during '{description}': {e}")
        return False


def check_prerequisites():
    """Verify that all prerequisites are in place."""
    logger.info("=" * 60)
    logger.info("STEP 1: Checking prerequisites")
    logger.info("=" * 60)

    errors = []

    # Check Python version
    py_version = sys.version_info
    logger.info(f"Python version: {py_version.major}.{py_version.minor}.{py_version.micro}")
    if py_version < (3, 8):
        errors.append("Python 3.8+ is required")

    # Check pip availability
    pip_available = run_command(
        [sys.executable, "-m", "pip", "--version"],
        "Checking pip availability",
    )
    if not pip_available:
        errors.append("pip is not available")

    # Check requirements.txt exists
    if not REQUIREMENTS_FILE.exists():
        errors.append(f"Requirements file not found: {REQUIREMENTS_FILE}")
    else:
        logger.info(f"Requirements file found: {REQUIREMENTS_FILE}")

    # Check source directory
    if SRC_DIR.exists():
        logger.info(f"Source directory found: {SRC_DIR}")
    else:
        logger.warning(f"Source directory not found at {SRC_DIR}, using project root")

    # Check tests directory
    if TEST_DIR.exists():
        test_files = list(TEST_DIR.glob("test_*.py")) + list(TEST_DIR.glob("*_test.py"))
        logger.info(f"Test directory found: {TEST_DIR} ({len(test_files)} test files)")
    else:
        # Also check for tests in project root
        test_files = list(PROJECT_ROOT.glob("test_*.py")) + list(PROJECT_ROOT.glob("*_test.py"))
        if test_files:
            logger.info(f"Found {len(test_files)} test files in project root")
        else:
            logger.warning("No test directory or test files found")

    if errors:
        for error in errors:
            logger.error(f"Prerequisite failed: {error}")
        return False

    logger.info("All prerequisites satisfied")
    return True


def install_dependencies():
    """Install project dependencies from requirements.txt."""
    logger.info("=" * 60)
    logger.info("STEP 2: Installing dependencies")
    logger.info("=" * 60)

    if not REQUIREMENTS_FILE.exists():
        logger.warning("No requirements.txt found, skipping dependency installation")
        return True

    # Upgrade pip first
    run_command(
        [sys.executable, "-m", "pip", "install", "--upgrade", "pip"],
        "Upgrading pip",
    )

    # Install production dependencies
    success = run_command(
        [
            sys.executable, "-m", "pip", "install",
            "-r", str(REQUIREMENTS_FILE),
            "--no-cache-dir",
            "--quiet",
        ],
        "Installing production dependencies",
    )

    if not success:
        return False

    # Install test dependencies if a test requirements file exists
    test_requirements = PROJECT_ROOT / "requirements-test.txt"
    if test_requirements.exists():
        success = run_command(
            [
                sys.executable, "-m", "pip", "install",
                "-r", str(test_requirements),
                "--no-cache-dir",
                "--quiet",
            ],
            "Installing test dependencies",
        )
        if not success:
            return False
    else:
        # Ensure pytest is available for running tests
        run_command(
            [sys.executable, "-m", "pip", "install", "pytest", "pytest-cov", "--quiet"],
            "Installing pytest (test runner)",
        )

    # Verify installed packages
    run_command(
        [sys.executable, "-m", "pip", "freeze"],
        "Listing installed packages",
    )

    return True


def run_linting():
    """Run code linting checks if linters are available."""
    logger.info("=" * 60)
    logger.info("STEP 3: Running linting checks")
    logger.info("=" * 60)

    target = str(SRC_DIR) if SRC_DIR.exists() else "."

    # Try flake8
    flake8_success = run_command(
        [sys.executable, "-m", "flake8", target, "--max-line-length=120", "--count", "--statistics"],
        "Running flake8 linting",
    )

    if not flake8_success:
        logger.warning("flake8 not available or linting issues found (non-blocking)")

    return True  # Linting is non-blocking but logged


def run_tests():
    """Run the application test suite."""
    logger.info("=" * 60)
    logger.info("STEP 4: Running tests")
    logger.info("=" * 60)

    # Determine test target
    test_target = str(TEST_DIR) if TEST_DIR.exists() else str(PROJECT_ROOT)

    # Check if there are any test files
    test_path = Path(test_target)
    test_files = list(test_path.rglob("test_*.py")) + list(test_path.rglob("*_test.py"))

    if not test_files:
        logger.warning("No test files found - skipping test execution")
        logger.warning("Consider adding tests before deploying to production!")
        return True

    logger.info(f"Found {len(test_files)} test file(s)")

    # Run pytest with coverage
    coverage_target = "src" if SRC_DIR.exists() else "."

    success = run_command(
        [
            sys.executable, "-m", "pytest",
            test_target,
            "-v",
            "--tb=short",
            f"--cov={coverage_target}",
            "--cov-report=term-missing",
            "--cov-fail-under=0",  # Set to desired threshold, e.g., 80
            "-x",  # Stop on first failure for faster feedback
            "--timeout=60",
        ],
        "Running test suite with coverage",
        env={"PYTHONPATH": str(PROJECT_ROOT)},
    )

    if not success:
        # Retry without coverage in case pytest-cov or pytest-timeout isn't installed
        logger.warning("Retrying tests without coverage plugin...")
        success = run_command(
            [
                sys.executable, "-m", "pytest",
                test_target,
                "-v",
                "--tb=short",
                "-x",
            ],
            "Running test suite (without coverage)",
            env={"PYTHONPATH": str(PROJECT_ROOT)},
        )

    return success


def clean_build_artifacts():
    """Clean previous build artifacts."""
    logger.info("Cleaning previous build artifacts...")

    for directory in [BUILD_DIR, DIST_DIR]:
        if directory.exists():
            shutil.rmtree(directory)
            logger.info(f"Removed: {directory}")

    # Clean __pycache__ directories
    for pycache in PROJECT_ROOT.rglob("__pycache__"):
        shutil.rmtree(pycache)

    # Clean .pyc files
    for pyc_file in PROJECT_ROOT.rglob("*.pyc"):
        pyc_file.unlink()

    logger.info("Build artifacts cleaned")


def should_exclude(path):
    """Check if a path should be excluded from the package."""
    parts = Path(path).parts
    for part in parts:
        if part in PACKAGE_EXCLUDES:
            return True
        for pattern in PACKAGE_EXCLUDES:
            if "*" in pattern and part.endswith(pattern.replace("*", "")):
                return True
    return False


def package_application():
    """Package the application for deployment."""
    logger.info("=" * 60)
    logger.info("STEP 5: Packaging application for deployment")
    logger.info("=" * 60)

    clean_build_artifacts()

    # Create build and dist directories
    BUILD_DIR.mkdir(parents=True, exist_ok=True)
    DIST_DIR.mkdir(parents=True, exist_ok=True)

    # Generate build metadata
    timestamp = datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")
    git_hash = "unknown"

    try:
        result = subprocess.run(
            ["git", "rev-parse", "--short", "HEAD"],
            capture_output=True, text=True, timeout=10,
        )
        if result.returncode == 0:
            git_hash = result.stdout.strip()
    except (FileNotFoundError, subprocess.TimeoutExpired):
        logger.warning("Git not available, using 'unknown' as commit hash")

    build_info = {
        "build_timestamp": timestamp,
        "git_commit": git_hash,
        "python_version": f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}",
        "builder": os.environ.get("USER", os.environ.get("USERNAME", "ci")),
        "ci_build_number": os.environ.get("BUILD_NUMBER", os.environ.get("GITHUB_RUN_NUMBER", "local")),
    }

    # Write build info
    build_info_path = BUILD_DIR / "build_info.json"
    with open(build_info_path, "w") as f:
        json.dump(build_info, f, indent=2)
    logger.info(f"Build info: {json.dumps(build_info, indent=2)}")

    # Copy application files to build directory
    files_copied = 0

    # Copy source files
    source_dir = SRC_DIR if SRC_DIR.exists() else PROJECT_ROOT
    for item in source_dir.rglob("*"):
        if item.is_file() and not should_exclude(item.relative_to(PROJECT_ROOT)):
            relative = item.relative_to(PROJECT_ROOT)
            dest = BUILD_DIR / relative
            dest.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(item, dest)
            files_copied += 1

    # Copy essential config files from project root
    essential_files = [
        "requirements.txt",
        "setup.py",
        "setup.cfg",
        "pyproject.toml",
        "Procfile",
        "Dockerfile",
        "docker-compose.yml",
        ".env.example",
        "alembic.ini",
        "gunicorn.conf.py",
        "wsgi.py",
        "manage.py",
        "app.py",
        "main.py",
    ]

    for filename in essential_files:
        filepath = PROJECT_ROOT / filename
        if filepath.exists():
            shutil.copy2(filepath, BUILD_DIR / filename)
            files_copied += 1
            logger.info(f"Included config file: {filename}")

    # Copy build info into build dir
    logger.info(f"Copied {files_copied} files to build directory")

    # Install production dependencies into the package
    vendor_dir = BUILD_DIR / "vendor"
    if REQUIREMENTS_FILE.exists():
        success = run_command(
            [
                sys.executable, "-m", "pip", "install",
                "-r", str(REQUIREMENTS_FILE),
                "--target", str(vendor_dir),
                "--no-cache-dir",
                "--quiet",
            ],
            "Vendoring production dependencies",
        )
        if not success:
            logger.warning("Failed to vendor dependencies, they must be installed at deploy time")

    # Create the deployment tarball
    package_name = f"deployment_{timestamp}_{git_hash}.tar.gz"
    package_path = DIST_DIR / package_name
    latest_path = DIST_DIR / "deployment_latest.tar.gz"

    logger.info(f"Creating deployment package: {package_name}")

    with tarfile.open(package_path, "w:gz") as tar:
        tar.add(BUILD_DIR, arcname="app")

    package_size = package_path.stat().st_size
    package_size_mb = package_size / (1024 * 1024)
    logger.info(f"Package created: {package_path} ({package_size_mb:.2f} MB)")

    # Create a "latest" symlink/copy for convenience
    if latest_path.exists():
        latest_path.unlink()
    shutil.copy2(package_path, latest_path)
    logger.info(f"Latest package: {latest_path}")

    # Write manifest
    manifest = {
        "package_name": package_name,
        "package_path": str(package_path),
        "package_size_bytes": package_size,
        "build_info": build_info,
        "files_included": files_copied,
    }

    manifest_path = DIST_DIR / "manifest.json"
    with open(manifest_path, "w") as f:
        json.dump(manifest, f, indent=2)

    logger.info(f"Manifest written: {manifest_path}")

    return True


def print_summary(results):
    """Print a summary of all pipeline steps."""
    logger.info("")
    logger.info("=" * 60)
    logger.info("DEPLOYMENT PIPELINE SUMMARY")
    logger.info("=" * 60)

    all_passed = True
    for step_name, passed in results.items():
        status = "✅ PASSED" if passed else "❌ FAILED"
        logger.info(f"  {step_name:<35} {status}")
        if not passed:
            all_passed = False

    logger.info("=" * 60)

    if all_passed:
        logger.info("🚀 DEPLOYMENT PACKAGE READY")
        logger.info(f"   Package location: {DIST_DIR}/")
    else:
        logger.error("❌ PIPELINE FAILED - Deployment aborted")

    logger.info("=" * 60)

    return all_passed


def main():
    """Main deployment pipeline orchestrator."""
    start_time = datetime.now(timezone.utc)

    logger.info("=" * 60)
    logger.info("DEPLOYMENT AUTOMATION PIPELINE")
    logger.info(f"Started: {start_time.isoformat()}")
    logger.info(f"Project: {PROJECT_ROOT}")
    logger.info("=" * 60)

    results = {}

    # Step 1: Prerequisites
    results["Check Prerequisites"] = check_prerequisites()
    if not results["Check Prerequisites"]:
        print_summary(results)
        sys.exit(1)

    # Step 2: Install Dependencies
    results["Install Dependencies"] = install_dependencies()
    if not results["Install Dependencies"]:
        print_summary(results)
        sys.exit(1)

    # Step 3: Linting (non-blocking)
    results["Code Linting"] = run_linting()

    # Step 4: Run Tests (blocking)
    results["Run Tests"] = run_tests()
    if not results["Run Tests"]:
        print_summary(results)
        sys.exit(1)

    # Step 5: Package Application
    results["Package Application"] = package_application()
    if not results["Package Application"]:
        print_summary(results)
        sys.exit(1)

    # Final summary
    end_time = datetime.now(timezone.utc)
    duration = (end_time - start_time).total_seconds()
    logger.info(f"Total pipeline duration: {duration:.1f}s")

    success = print_summary(results)
    sys.exit(0 if success else 1)


if __name__ == "__main__":
    main()